mapper.select:
SELECT
    p.property_deal_id,
    p.property_type,
    p.deal_type,
    p.source_id,
    p.lawd_cd,
    COALESCE(NULLIF(p.sido_name, ''), r.sido_name) AS sido_name,
    COALESCE(NULLIF(p.gugun_name, ''), r.gugun_name) AS gugun_name,
    p.dong_name,
    p.property_name,
    p.deal_date,
    p.deal_amount,
    p.deposit_amount,
    p.monthly_rent_amount,
    p.exclusive_area,
    p.floor,
    p.build_year,
    p.jibun,
    p.latitude,
    p.longitude,
    p.source
FROM property_deal_cache p
LEFT JOIN (
    SELECT DISTINCT LEFT(dong_code, 5) AS lawd_cd, sido_name, gugun_name
    FROM dongcodes
    WHERE dong_code IS NOT NULL AND LENGTH(dong_code) >= 5
) r ON r.lawd_cd = p.lawd_cd


        AND p.property_type = #{propertyType}


        AND p.deal_type = #{dealType}


        AND p.lawd_cd = #{lawdCd}


        AND COALESCE(NULLIF(p.sido_name, ''), r.sido_name) = #{sidoName}


        AND COALESCE(NULLIF(p.gugun_name, ''), r.gugun_name) = #{gugunName}


        AND p.dong_name = #{dongName}



        AND (
            p.property_name LIKE #{keywordLike}
            OR COALESCE(NULLIF(p.sido_name, ''), r.sido_name) LIKE #{keywordLike}
            OR COALESCE(NULLIF(p.gugun_name, ''), r.gugun_name) LIKE #{keywordLike}
            OR p.dong_name LIKE #{keywordLike}
            OR p.jibun LIKE #{keywordLike}
        )


ORDER BY p.deal_date DESC, p.property_deal_id DESC
LIMIT #{limit}
